#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#include <stdbool.h>
#define N 200001
#define INF 1000000000000000000LL
typedef struct {
    int vertex;
    long long distance;
} Node;
typedef struct {
    Node *nodes;
    int size;
} MinHeap;
int main() {
    int T = 1;
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        long long d[N];
        for (int i = 0; i < N; i++) {
            d[i] = INF;
        }
        d[0] = 0;
        // Create adjacency list
        int adj[N][N] = {0};
        for (int i = 0; i < M; i++) {
            int u, v, w;
            scanf("%d %d %d", &u, &v, &w);
            adj[u - 1][v - 1] = w;
            adj[v - 1][u - 1] = w;
        }
        // Dijkstra's algorithm
        bool vis[N] = {false};
        for (int i = 0; i < N; i++) {
            int u = -1;
            for (int j = 0; j < N; j++) {
                if (!vis[j] && (u == -1 || d[j] < d[u])) {
                    u = j;
                }
            }
            vis[u] = true;
            for (int v = 0; v < N; v++) {
                if (adj[u][v] > 0 && d[u] + adj[u][v] < d[v]) {
                    d[v] = d[u] + adj[u][v];
                }
            }
        }
        // Print distances
        for (int i = 0; i < N; i++) {
            if (d[i] == INF) {
                printf("-1 ");
            } else {
                printf("%lld ", d[i]);
            }
        }
        printf("\n");
    }
    return 0;
}

