const int N = 2e5 + 1;
const long long INF = 1e18;
long long d[N];
vector<pair<int, int>> adj[N];
bool vis[N];
int main() {
    int T = 1;
    while (T--) {
        int N, M;
        cin >> N >> M;
        for (int i = 0; i < N; i++) {
            d[i] = INF;
        }
        d[0] = 0;
        for (int i = 0; i < M; i++) {
            int u, v, w;
            cin >> u >> v >> w;
            adj[u - 1].push_back({v - 1, w});
            adj[v - 1].push_back({u - 1, w});
        }
        priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;
        pq.push({0, 0});
        while (!pq.empty()) {
            int u = pq.top().second;
            pq.pop();
            if (vis[u]) continue;
            vis[u] = true;
            for (auto &p : adj[u]) {
                int v = p.first;
                int w = p.second;
                if (d[u] + w < d[v]) {
                    d[v] = d[u] + w;
                    pq.push({d[v], v});
                }
            }
        }
        for (int i = 0; i < N; i++) {
            if (d[i] == INF) {
