import java.util.*;
class Main {
    static final int N = 200001;
    static final long INF = (long)1e18;
    static long[] d = new long[N];
    static List<Pair>[] adj = new ArrayList[N];
    static boolean[] vis = new boolean[N];
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = 1;
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            for (int i = 0; i < N; i++) {
                d[i] = INF;
            }
            d[0] = 0;
            for (int i = 0; i < N; i++) {
                adj[i] = new ArrayList<>();
            }
            for (int i = 0; i < M; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                int w = sc.nextInt();
                adj[u].add(new Pair(v, w));
                adj[v].add(new Pair(u, w));
            }
            PriorityQueue<Pair> pq = new PriorityQueue<>((a, b) -> Long.compare(a.w, b.w));
            pq.add(new Pair(0, 0));
            while (!pq.isEmpty()) {
                Pair p = pq.poll();
                int u = p.v;
                if (vis[u]) continue;
                vis[u] = true;
                for (Pair pair : adj[u]) {
                    int v = pair.v;
                    int w = pair.w;
                    if (d[u] + w < d[v]) {
                        d[v] = d[u] + w;
                        pq.add(new Pair(d[v], v));
                    }
                }
            }
            for (int i = 0; i < N; i++) {
                if (d[i] == INF) {
                    System.out.print(-1 + " ");
                } else {
                    System.out.print(d[i] + " ");
                }
            }
            System.out.println();
        }
    }
    static class Pair {
        int v;
        long w;
        Pair(int v, long w) {
            this.v = v;
            this.w = w;
        }
    }
}

