const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const N = 200001;
const INF = 1000000000000000000;
let d = new Array(N).fill(INF);
let adj = new Array(N).fill(0).map(() => []);
let vis = new Array(N).fill(false);
function main() {
    let T = 1;
    while (T-- > 0) {
        let [N, M] = lines[idx++].trim().split(' ').map(Number);
        for (let i = 0; i < N; i++) {
            d[i] = INF;
        }
        d[0] = 0;
        for (let i = 0; i < M; i++) {
            let [u, v, w] = lines[idx++].trim().split(' ').map(Number);
            adj[u - 1].push([v - 1, w]);
            adj[v - 1].push([u - 1, w]);
        }
        let pq = [[0, 0]];
        while (pq.length > 0) {
            pq.sort((a, b) => a[0] - b[0]);
            let [dist, u] = pq.shift();
            if (vis[u]) continue;
            vis[u] = true;
            for (let i = 0; i < adj[u].length; i++) {
                let [v, w] = adj[u][i];
                if (dist + w < d[v]) {
                    d[v] = dist + w;
                    pq.push([d[v], v]);
                }
            }
        }
        let result = '';
        for (let i = 0; i < N; i++) {
            if (d[i] == INF) {
                result += '-1 ';
            } else {
                result += d[i] + ' ';
            }
        }
        console.log(result);
    }
}
main();
